1	// jnxfh_main.cpp — the jnxfh feed handler process (JNX_PLAN2.md F5).
2	//
3	// Flow: cfg -> DB connect + HELLO -> recovery or bootstrap -> live loop
4	// (reactor): soup packet -> itch decode -> market.apply -> one UPDATE per
5	// applied message (except 'T') -> DB write FIRST, then multicast send.
6	// Single-threaded: DB reconnect is a reactor timer, never a thread.
7	//
8	// Config keys (file via --config=..., overridden by --key=value):
9	//   itch_host itch_port glimpse_host glimpse_port user pass
10	//   db_sock mcast_group mcast_port mcast_ttl mcast_if
11	//   bootstrap (replay|glimpse)  require_db (0|1)
12	#include <signal.h>
13	#include <unistd.h>
14	
15	#include <cstdio>
16	#include <cstring>
17	#include <string>
18	#include <vector>
19	
20	#include "common/cfg.h"
21	#include "common/log.h"
22	#include "common/time.h"
23	#include "fh/glimpse.h"
24	#include "fh/publish.h"
25	#include "fh/reactor.h"
26	#include "fh/recover.h"
27	#include "fh/soupclient.h"
28	#include "itch/itch.h"
29	#include "market/market.h"
30	#include "wire/record.h"
31	
32	namespace {
33	
34	const char* COMP = "jnxfh";
35	
36	volatile sig_atomic_t g_stop = 0;
37	
38	void on_signal(int) {
39	    g_stop = 1;
40	}
41	
42	struct Fh {
43	    // config
44	    std::string db_sock;
45	    bool require_db;
46	
47	    // state
48	    jnx::Market market;
49	    jnx::PubContext ctx;
50	    jnx::DbLink db;
51	    jnx::McastSender mcast;
52	    uint64_t epoch;
53	    uint64_t pub_seq;         // last published pub_seq (starts 0, first is 1)
54	    uint64_t last_exch_seq;   // last APPLIED exchange seq (incl. T)
55	    std::string session;      // current exchange session id
56	    bool db_connected;
57	
58	    // stats
59	    uint64_t published;
60	    uint64_t db_write_fails;
61	    uint64_t decode_errors;
62	    uint64_t msgs_since_stats;
63	
64	    int exit_code;
65	
66	    Fh() : require_db(false), epoch(0), pub_seq(0), last_exch_seq(0),
67	           db_connected(false), published(0), db_write_fails(0),
68	           decode_errors(0), msgs_since_stats(0), exit_code(0) {}
69	
70	    // RESET + full SYNC dump from our own market state.
71	    bool push_full_sync() {
72	        std::vector<unsigned char> out;
73	        unsigned char ctl[jnx::CONTROL_WIRE_SIZE];
74	        size_t n = jnx::encode_control(jnx::KIND_RESET, ctl);
75	        out.insert(out.end(), ctl, ctl + n);
76	        jnx::build_sync_dump(market, ctx, session, last_exch_seq, epoch, out);
77	        if (!db.send(&out[0], out.size())) {
78	            db_connected = false;
79	            return false;
80	        }
81	        LOG_INFO(COMP) << "pushed RESET + full sync to db (" << out.size()
82	                       << " bytes, last_seq=" << last_exch_seq << ")";
83	        return true;
84	    }
85	
86	    // (Re)establish the DB link; on success sync if needed. Returns
87	    // db_connected.
88	    bool try_db_connect() {
89	        jnx::HelloRecord db_hello;
90	        if (!db.connect_hello(db_sock, epoch, last_exch_seq, db_hello)) {
91	            return false;
92	        }
93	        db_connected = true;
94	        LOG_INFO(COMP) << "db connected (db epoch=" << db_hello.epoch
95	                       << " last_seq=" << db_hello.last_exch_seq << ")";
96	        // Anything other than an exact match of our position means the DB
97	        // is empty/stale/from another life: rebase it from our state.
98	        if (db_hello.epoch != epoch ||
99	            db_hello.last_exch_seq != last_exch_seq) {
100	            if (!push_full_sync()) {
101	                return false;
102	            }
103	        }
104	        return db_connected;
105	    }
106	};
107	
108	} // namespace
109	
110	int main(int argc, char** argv) {
111	    jnx::Cfg cfg;
112	    // Optional config file first, then --key=value overrides.
113	    for (int i = 1; i < argc; ++i) {
114	        if (std::strncmp(argv[i], "--config=", 9) == 0) {
115	            if (!cfg.load_file(argv[i] + 9)) {
116	                std::fprintf(stderr, "jnxfh: cannot read config %s\n",
117	                             argv[i] + 9);
118	                return 2;
119	            }
120	        }
121	    }
122	    cfg.apply_args(argc, argv);
123	
124	    const std::string itch_host = cfg.get("itch_host", "127.0.0.1");
125	    const int itch_port = static_cast<int>(cfg.get_int("itch_port", 15001));
126	    const std::string glimpse_host =
127	        cfg.get("glimpse_host", cfg.get("itch_host", "127.0.0.1"));
128	    const int glimpse_port =
129	        static_cast<int>(cfg.get_int("glimpse_port", 15002));
130	    const std::string user = cfg.get("user", "TEST");
131	    const std::string pass = cfg.get("pass", "SECRET");
132	    const std::string bootstrap = cfg.get("bootstrap", "replay");
133	    const std::string mcast_group = cfg.get("mcast_group", "239.192.1.1");
134	    const int mcast_port = static_cast<int>(cfg.get_int("mcast_port", 26400));
135	    const int mcast_ttl = static_cast<int>(cfg.get_int("mcast_ttl", 1));
136	    const std::string mcast_if = cfg.get("mcast_if", "");
137	
138	    Fh fh;
139	    fh.db_sock = cfg.get("db_sock", "/tmp/jnx-db.sock");
140	    fh.require_db = cfg.get_int("require_db", 0) != 0;
141	    fh.epoch = jnx::now_ns(); // provisional; recovery may adopt the DB's
142	
143	    signal(SIGINT, on_signal);
144	    signal(SIGTERM, on_signal);
145	    signal(SIGPIPE, SIG_IGN);
146	
147	    if (!fh.mcast.open(mcast_group, mcast_port, mcast_ttl, mcast_if)) {
148	        return 2;
149	    }
150	
151	    // ---- startup decision tree (restart matrix) --------------------------
152	    std::string login_session; // requested session for the ITCH login
153	    uint64_t login_seq = 1;
154	
155	    jnx::HelloRecord db_hello;
156	    bool db_up = fh.db.connect_hello(fh.db_sock, 0, 0, db_hello);
157	    if (!db_up && fh.require_db) {
158	        LOG_ERROR(COMP) << "db unavailable at " << fh.db_sock
159	                        << " and require_db=1";
160	        return 3;
161	    }
162	
163	    if (db_up && (db_hello.epoch != 0 || db_hello.last_exch_seq != 0)) {
164	        // DB has state: recover and resume (zero replay).
165	        jnx::RecoveredMeta meta;
166	        if (recover_from_db(fh.db, fh.market, fh.ctx, meta)) {
167	            fh.session = meta.session;
168	            fh.last_exch_seq = meta.last_exch_seq;
169	            fh.epoch = meta.epoch;
170	            fh.db_connected = true;
171	            login_session = meta.session;
172	            login_seq = meta.last_exch_seq + 1;
173	            LOG_INFO(COMP) << "resume mode: session='" << login_session
174	                           << "' seq=" << login_seq;
175	        } else {
176	            LOG_ERROR(COMP) << "db recovery failed; falling back to "
177	                            << bootstrap << " bootstrap with a fresh market";
178	            fh.market = jnx::Market();
179	            fh.ctx = jnx::PubContext();
180	            db_up = fh.db.connect_hello(fh.db_sock, fh.epoch,
181	                                        fh.last_exch_seq, db_hello);
182	        }
183	    }
184	
185	    if (login_seq == 1 && login_session.empty()) {
186	        // No recovered state: cold bootstrap.
187	        if (bootstrap == "glimpse") {
188	            jnx::GlimpseResult gr;
189	            const char* err = NULL;
190	            if (!jnx::glimpse_bootstrap(glimpse_host, glimpse_port, user,
191	                                        pass, fh.market, gr, &err)) {
192	                LOG_ERROR(COMP) << "glimpse bootstrap failed: "
193	                                << (err ? err : "?");
194	                return 4;
195	            }
196	            fh.session = gr.session;
197	            fh.last_exch_seq = gr.next_live_seq - 1;
198	            login_session = ""; // blank = current session (spec-safe)
199	            login_seq = gr.next_live_seq;
200	        } else if (bootstrap == "replay") {
201	            login_session = "";
202	            login_seq = 1;
203	            fh.last_exch_seq = 0;
204	        } else {
205	            LOG_ERROR(COMP) << "unknown bootstrap mode: " << bootstrap;
206	            return 2;
207	        }
208	        if (db_up) {
209	            fh.db_connected = true;
210	            if (!fh.push_full_sync()) {
211	                LOG_WARN(COMP) << "initial sync failed; will retry";
212	            }
213	        }
214	    }
215	
216	    // ---- live loop --------------------------------------------------------
217	    jnx::Reactor reactor;
218	    jnx::SoupClientSession session(user, pass, login_session, login_seq);
219	    jnx::TcpSoupConnector connector(reactor, itch_host, itch_port, session);
220	
221	    session.on_login_accepted = [&](const std::string& sid, uint64_t seq) {
222	        fh.session = sid;
223	        LOG_INFO(COMP) << "logged in: session='" << sid << "' next seq "
224	                       << seq;
225	    };
226	    session.on_login_rejected = [&](char code) {
227	        LOG_ERROR(COMP) << "login rejected with code '" << code
228	                        << "' — terminating (no retry)";
229	        fh.exit_code = 5;
230	        connector.stop();
231	        reactor.stop();
232	    };
233	    session.on_end_of_session = [&]() {
234	        LOG_INFO(COMP) << "end of session (Z): published=" << fh.published
235	                       << " last_seq=" << fh.last_exch_seq
236	                       << " pub_seq=" << fh.pub_seq;
237	        session.logout(jnx::mono_ns());
238	        connector.flush();
239	        connector.stop();
240	        reactor.stop();
241	    };
242	    session.on_peer_silent = [&]() {
243	        LOG_WARN(COMP) << "peer silent for 15 s; reconnecting";
244	        connector.reconnect();
245	    };
246	    session.on_message = [&](uint64_t seq, const unsigned char* payload,
247	                             size_t len) {
248	        jnx::ItchMsg msg;
249	        const char* err = NULL;
250	        if (!jnx::decode(payload, len, msg, &err)) {
251	            ++fh.decode_errors;
252	            LOG_WARN(COMP) << "itch decode error at seq " << seq << ": "
253	                           << (err ? err : "?");
254	            return;
255	        }
256	        jnx::ApplyResult res = fh.market.apply(msg);
257	        fh.last_exch_seq = seq;
258	        ++fh.msgs_since_stats;
259	        if (!res.applied || res.trigger == 'T') {
260	            return; // T updates the clock but publishes nothing (pinned)
261	        }
262	        uint64_t exch_ns =
263	            jnx::make_timestamp(fh.market.seconds, msg.type == 'T' ? 0 : msg.ns);
264	        if (res.trigger == 'S') {
265	            fh.ctx.note_event(res.group, msg.event);
266	        }
267	        fh.ctx.note(res, exch_ns);
268	
269	        jnx::Envelope env;
270	        env.epoch = fh.epoch;
271	        env.pub_seq = ++fh.pub_seq;
272	        env.session = fh.session;
273	        env.exch_seq = seq;
274	        env.exch_ns = exch_ns;
275	        env.trigger = res.trigger;
276	        jnx::UpdateRecord rec = jnx::make_update(fh.market, fh.ctx, res, env);
277	        unsigned char buf[jnx::UPDATE_WIRE_SIZE];
278	        size_t n = jnx::encode_update(rec, buf);
279	        // DB write FIRST (authoritative), then multicast.
280	        if (fh.db_connected) {
281	            if (!fh.db.send(buf, n)) {
282	                fh.db_connected = false;
283	                ++fh.db_write_fails;
284	            }
285	        }
286	        fh.mcast.send(buf, n);
287	        ++fh.published;
288	    };
289	
290	    // DB reconnect loop: a 1 s reactor timer, never a thread.
291	    std::function<void()> db_timer_fn;
292	    db_timer_fn = [&]() {
293	        if (!fh.db_connected) {
294	            if (fh.try_db_connect()) {
295	                LOG_INFO(COMP) << "db link restored";
296	            }
297	        }
298	        reactor.call_later(1000000000ULL, db_timer_fn);
299	    };
300	    reactor.call_later(1000000000ULL, db_timer_fn);
301	
302	    // Signal watcher + clean shutdown.
303	    std::function<void()> sig_timer_fn;
304	    sig_timer_fn = [&]() {
305	        if (g_stop) {
306	            LOG_INFO(COMP) << "signal received; shutting down cleanly";
307	            session.logout(jnx::mono_ns());
308	            connector.flush();
309	            connector.stop();
310	            reactor.stop();
311	            return;
312	        }
313	        reactor.call_later(200000000ULL, sig_timer_fn);
314	    };
315	    reactor.call_later(200000000ULL, sig_timer_fn);
316	
317	    // 5 s stats line.
318	    std::function<void()> stats_timer_fn;
319	    stats_timer_fn = [&]() {
320	        LOG_INFO(COMP) << "stats: msgs/s=" << fh.msgs_since_stats / 5
321	                       << " exch_seq=" << fh.last_exch_seq
322	                       << " pub_seq=" << fh.pub_seq
323	                       << " books=" << fh.market.books.books().size()
324	                       << " orders=" << fh.market.books.orders().size()
325	                       << " db_connected=" << (fh.db_connected ? 1 : 0)
326	                       << " mcast_errors=" << fh.mcast.send_errors();
327	        fh.msgs_since_stats = 0;
328	        reactor.call_later(5000000000ULL, stats_timer_fn);
329	    };
330	    reactor.call_later(5000000000ULL, stats_timer_fn);
331	
332	    LOG_INFO(COMP) << "starting live loop: itch " << itch_host << ":"
333	                   << itch_port << ", db " << fh.db_sock << " (connected="
334	                   << (fh.db_connected ? 1 : 0) << "), epoch=" << fh.epoch;
335	    connector.start();
336	    reactor.run();
337	
338	    LOG_INFO(COMP) << "exit: published=" << fh.published
339	                   << " pub_seq=" << fh.pub_seq << " last_exch_seq="
340	                   << fh.last_exch_seq << " decode_errors="
341	                   << fh.decode_errors << " db_write_fails="
342	                   << fh.db_write_fails;
343	    return fh.exit_code;
344	}
